TEMPLATE_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "template.xlsx")
if not os.path.exists(TEMPLATE_PATH):
    with open(TEMPLATE_PATH, "wb") as f:
        f.write(base64.b64decode(_TEMPLATE_B64))

WORKBOOK_NAME = os.path.basename(TEMPLATE_PATH)
DATA_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "periods_data.json")

KPI_CELLS = {
    "Umsatz (MEUR)": ("2 Finanzen", "B7"),
    "EBIT (MEUR)": ("2 Finanzen", "B18"),
    "EBITDA (MEUR)": ("2 Finanzen", "B50"),
    "Periodenüberschuss (MEUR)": ("2 Finanzen", "B40"),
    "Eigenkapitalquote": ("5 Kredite & Aktienkurs", "B32"),
    "Aktienkurs (EUR)": ("5 Kredite & Aktienkurs", "B54"),
}

CHART_RANGES = {
    "DB-Treppe (DB I–V, MEUR)": ("0 Dashboard", ["J18", "J19", "J20", "J21", "J22"], ["DB I", "DB II", "DB III", "DB IV", "DB V"]),
    "Kostenstruktur GuV (MEUR)": ("0 Dashboard", ["J25", "J26", "J27", "J28"], ["Material", "Personal", "Abschreibungen", "Sonstiger Aufwand"]),
    "Auslastung Anlagen vs. Mitarbeiter": ("0 Dashboard", ["J31", "J32"], ["Anlagen", "Mitarbeiter"]),
    "Bilanzstruktur (MEUR)": ("0 Dashboard", ["J36", "J37", "J40", "J41", "J42"], ["Anlagevermögen", "Umlaufvermögen", "Eigenkapital", "Pensionsrückstellungen", "Verbindlichkeiten"]),
}


@st.cache_resource(show_spinner=False)
def get_model():
    return formulas.ExcelModel().loads(TEMPLATE_PATH).finish()


@st.cache_resource(show_spinner=False)
def get_meta():
    return json.loads(_INPUTS_META_JSON)


@st.cache_resource(show_spinner=False)
def get_structure():
    return json.loads(_STRUCTURE_JSON)


def key_for(sheet, cell):
    return f"'[{WORKBOOK_NAME}]{sheet.upper()}'!{cell}"


def load_periods():
    if os.path.exists(DATA_PATH):
        return json.load(open(DATA_PATH, encoding="utf-8"))
    return {"0": {}}


def save_periods(periods):
    json.dump(periods, open(DATA_PATH, "w", encoding="utf-8"), ensure_ascii=False, indent=1)


@st.cache_resource(show_spinner="Berechne Periode...")
def calculate(overrides_tuple):
    overrides = dict(overrides_tuple)
    xl = get_model()
    inputs = {key_for(sheet, cell): val for (sheet, cell), val in overrides.items()}
    sol = xl.calculate(inputs=inputs)
    return sol


def get_value(sol, sheet, cell):
    try:
        v = sol[key_for(sheet, cell)].value
        try:
            v = v[0][0]
        except Exception:
            pass
        return v
    except Exception:
        return None


def overrides_for_period(periods, pid):
    base = {}
    p = periods.get(pid, {})
    for sheet, cells in p.items():
        for cell, val in cells.items():
            base[(sheet, cell)] = val
    return base


def fmt(v, decimals=2, pct=False):
    if v is None:
        return "–"
    try:
        if pct:
            return f"{v*100:.1f} %"
        return f"{v:,.{decimals}f}".replace(",", "X").replace(".", ",").replace("X", ".")
    except Exception:
        return str(v)


# ---------- Session / Daten ----------
if "periods" not in st.session_state:
    st.session_state.periods = load_periods()
periods = st.session_state.periods

meta = get_meta()
sheets_order = ["1 Absatzplanung", "2 Finanzen", "3 Fertigung", "4 Personal", "5 Kredite & Aktienkurs"]

st.title("📊 Unternehmerisches Handeln – Analysetool")

# ---------- Sidebar: Periodenwahl ----------
st.sidebar.header("Perioden")
period_ids = sorted(periods.keys(), key=lambda x: int(x))
selected = st.sidebar.selectbox("Aktive Periode", period_ids, index=len(period_ids) - 1,
                                 format_func=lambda x: f"Periode {x}" + (" (Ausgangsdaten)" if x == "0" else ""))

st.sidebar.markdown("---")
new_base = st.sidebar.selectbox("Neue Periode aufbauen auf...", period_ids,
                                 format_func=lambda x: f"Periode {x}")
if st.sidebar.button("➕ Neue Periode erstellen"):
    next_id = str(max(int(x) for x in period_ids) + 1)
    periods[next_id] = copy.deepcopy(periods.get(new_base, {}))
    save_periods(periods)
    st.session_state.periods = periods
    st.rerun()

if selected != "0" and st.sidebar.button(f"🗑️ Periode {selected} löschen"):
    del periods[selected]
    save_periods(periods)
    st.session_state.periods = periods
    st.rerun()

overrides = overrides_for_period(periods, selected)
sol = calculate(tuple(sorted(overrides.items())))

tab_dash, tab_input, tab_hist, tab_export = st.tabs(["📈 Dashboard", "✏️ Eingaben", "📉 Verlauf", "⬇️ Export"])

# ---------- Dashboard ----------
with tab_dash:
    st.subheader(f"Dashboard – Periode {selected}")
    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Umsatz Gesamt (MEUR)", fmt(get_value(sol, "2 Finanzen", "B7")))
    c2.metric("EBIT (MEUR)", fmt(get_value(sol, "2 Finanzen", "B18")))
    c3.metric("EBITDA (MEUR)", fmt(get_value(sol, "2 Finanzen", "B50")))
    c4.metric("Periodenüberschuss (MEUR)", fmt(get_value(sol, "2 Finanzen", "B40")))

    c5, c6, c7, c8 = st.columns(4)
    c5.metric("Umsatzrendite", fmt(get_value(sol, "2 Finanzen", "B40") / get_value(sol, "2 Finanzen", "B7") if get_value(sol, "2 Finanzen", "B7") else None, pct=True))
    c6.metric("Eigenkapitalquote", fmt(get_value(sol, "5 Kredite & Aktienkurs", "B32"), pct=True))
    c7.metric("Aktienkurs (EUR)", fmt(get_value(sol, "5 Kredite & Aktienkurs", "B54")))
    c8.metric("Rating", str(get_value(sol, "5 Kredite & Aktienkurs", "B25")))

    st.markdown("---")
    cc1, cc2 = st.columns(2)
    with cc1:
        sheet, cells, labels = CHART_RANGES["DB-Treppe (DB I–V, MEUR)"]
        vals = [get_value(sol, sheet, c) for c in cells]
        fig = go.Figure(go.Bar(x=labels, y=vals, marker_color="#2563eb"))
        fig.update_layout(title="Deckungsbeitragstreppe (DB I–V, MEUR)", height=350)
        st.plotly_chart(fig, use_container_width=True)

        sheet, cells, labels = CHART_RANGES["Auslastung Anlagen vs. Mitarbeiter"]
        vals = [get_value(sol, sheet, c) for c in cells]
        fig = go.Figure(go.Bar(x=labels, y=[v * 100 if v else 0 for v in vals], marker_color="#16a34a"))
        fig.update_layout(title="Auslastung Anlagen vs. Mitarbeiter (%)", height=350)
        st.plotly_chart(fig, use_container_width=True)

    with cc2:
        sheet, cells, labels = CHART_RANGES["Kostenstruktur GuV (MEUR)"]
        vals = [get_value(sol, sheet, c) for c in cells]
        fig = go.Figure(go.Pie(labels=labels, values=vals))
        fig.update_layout(title="Kostenstruktur GuV (MEUR)", height=350)
        st.plotly_chart(fig, use_container_width=True)

        sheet, cells, labels = CHART_RANGES["Bilanzstruktur (MEUR)"]
        vals = [get_value(sol, sheet, c) for c in cells]
        fig = go.Figure(go.Bar(x=labels, y=vals, marker_color="#d97706"))
        fig.update_layout(title="Bilanzstruktur Aktiva vs. Passiva (MEUR)", height=350)
        st.plotly_chart(fig, use_container_width=True)

# ---------- Eingaben ----------
with tab_input:
    if selected == "0":
        st.info("Periode 0 enthält die fixen Ausgangsdaten aus der Excel-Datei und kann nicht verändert werden. Erstelle eine neue Periode, um Werte anzupassen.")
    else:
        st.subheader(f"Eingabewerte bearbeiten – Periode {selected}")
        st.caption("Werte direkt in der Tabelle ändern. Berechnete Spalten (z. B. % vom Umsatz) aktualisieren sich nach dem Speichern automatisch.")
        structure = get_structure()
        sheet_tabs = st.tabs(sheets_order)
        new_overrides = {}
        for sheet, st_tab in zip(sheets_order, sheet_tabs):
            with st_tab:
                items = [m for m in meta if m["sheet"] == sheet]
                by_major_sub = {}
                for m in items:
                    by_major_sub.setdefault((m.get("major") or sheet, m.get("sub")), []).append(m)

                for group in structure.get(sheet, []):
                    major = group["title"]
                    has_any_inputs = any(k[0] == major for k in by_major_sub)
                    with st.expander(f"**{major}**", expanded=has_any_inputs):
                        for sub in group["subs"]:
                            sub_title = sub["title"]
                            key = (major, sub_title)
                            sub_items = by_major_sub.get(key, [])
                            if sub_items:
                                if sub_title:
                                    st.markdown(f"**{sub_title}**")

                                has_text = any(isinstance(m["value"], str) for m in sub_items)
                                if has_text:
                                    cols = st.columns(2)
                                    for i, m in enumerate(sub_items):
                                        label = m["label"]
                                        if m.get("col_label"):
                                            label = f"{label} – {m['col_label']}"
                                        cur = periods.get(selected, {}).get(sheet, {}).get(m["cell"], m["value"])
                                        with cols[i % 2]:
                                            val = st.text_input(label, value=str(cur), key=f"{sheet}_{m['cell']}")
                                        new_overrides.setdefault(sheet, {})[m["cell"]] = val
                                else:
                                    sib_labels = []
                                    for m in sub_items:
                                        for s in m.get("siblings", []):
                                            if s["label"] not in sib_labels:
                                                sib_labels.append(s["label"])

                                    rows = []
                                    for m in sub_items:
                                        label = m["label"]
                                        if m.get("col_label"):
                                            label = f"{label} – {m['col_label']}"
                                        cur = periods.get(selected, {}).get(sheet, {}).get(m["cell"], m["value"])
                                        row = {"Position": label, "Wert": float(cur)}
                                        sib_map = {s["label"]: s["cell"] for s in m.get("siblings", [])}
                                        for sl in sib_labels:
                                            if sl in sib_map:
                                                row[sl] = get_value(sol, sheet, sib_map[sl])
                                            else:
                                                row[sl] = None
                                        rows.append(row)

                                    df = pd.DataFrame(rows)
                                    disabled_cols = ["Position"] + sib_labels
                                    edited = st.data_editor(
                                        df, key=f"editor_{sheet}_{major}_{sub_title}",
                                        disabled=disabled_cols, hide_index=True,
                                        use_container_width=True,
                                    )
                                    for i, m in enumerate(sub_items):
                                        new_overrides.setdefault(sheet, {})[m["cell"]] = edited.loc[i, "Wert"]
                                st.markdown("")
                            elif sub["rows"]:
                                if sub_title:
                                    st.caption(f"{sub_title} (Referenztabelle, nicht editierbar)")
                                else:
                                    st.caption("Referenztabelle, nicht editierbar")
                                st.table(sub["rows"])
        if st.button("💾 Periode speichern & neu berechnen", type="primary"):
            periods[selected] = new_overrides
            save_periods(periods)
            st.session_state.periods = periods
            st.cache_data.clear()
            st.cache_resource.clear()
            st.success("Gespeichert.")
            st.rerun()

# ---------- Verlauf ----------
with tab_hist:
    st.subheader("Verlauf über alle Perioden")
    history = {k: [] for k in KPI_CELLS}
    x_labels = []
    for pid in period_ids:
        ov = overrides_for_period(periods, pid)
        s = calculate(tuple(sorted(ov.items())))
        x_labels.append(f"P{pid}")
        for kpi, (sheet, cell) in KPI_CELLS.items():
            history[kpi].append(get_value(s, sheet, cell))

    for kpi, values in history.items():
        fig = go.Figure(go.Scatter(x=x_labels, y=values, mode="lines+markers", line=dict(width=3)))
        fig.update_layout(title=kpi, height=300, margin=dict(t=40, b=20))
        st.plotly_chart(fig, use_container_width=True)

# ---------- Export ----------
with tab_export:
    st.subheader(f"Export Periode {selected}")
    if st.button("Excel-Export erzeugen"):
        wb = openpyxl.load_workbook(TEMPLATE_PATH, data_only=False)
        for sheet, cells in periods.get(selected, {}).items():
            ws = wb[sheet]
            for cell, val in cells.items():
                ws[cell] = val
        out_path = f"/tmp/Periode_{selected}_export.xlsx"
        wb.save(out_path)
        # zusätzlich berechnete Werte als zweites Blatt anhängen
        wb2 = openpyxl.load_workbook(out_path)
        res = wb2.create_sheet("Berechnete_Kennzahlen")
        res.append(["Kennzahl", "Wert"])
        for kpi, (sheet, cell) in KPI_CELLS.items():
            res.append([kpi, get_value(sol, sheet, cell)])
        wb2.save(out_path)
        with open(out_path, "rb") as f:
            st.download_button("📥 Excel-Datei herunterladen", f, file_name=f"Periode_{selected}.xlsx")
